function Home() {
  return (
    <div className="w-full h-[100vh] flex items-center justify-center p-10 relative">
      <div
        className="absolute top-0 left-0 w-full h-full"
        style={{
          backgroundImage: "url('/fondo6.jpg')",
          backgroundSize: 'cover',
          backgroundPosition: 'center',
          backdropFilter: 'blur(5px)',
        }}
      />
      <div className="w-full h-full bg-red-600 z-20 flex items-center">
        {/* Images left */}
        <div className="w-full h-full relative flex items-center">
          <div className="ml-40 h-[60%] bg-blue-900">
            {/* <img
              className="rounded-lg absolute top-0 left-0 z-10 transition-transform transform hover:scale-110"
