              className="rounded-lg transition-transform transform hover:scale-110"
              width={300}
              height={300}
              src="/Foto1.HEIC"
              alt="Imagen 1"
            />
            <img
              className="rounded-lg transition-transform transform hover:scale-110"
              width={150}
              height={150}
              src="/Foto3.HEIC"
              alt="Imagen 2"
            />
          </div>
        </div>
        {/* Text center */}
        <div className="w-full h-full flex flex-col items-center z-10">
          <h1 className="text-black text-4xl md:text-6xl font-bold text-center">
            ¡Los invitamos a festejar nuestra boda!
          </h1>
          <h2 className="text-black text-4xl md:text-6xl font-bold text-center">
            Anto & Kevin
          </h2>
          <a
            href="#ConfirmAttendance"
            className="text-white text-xl mt-4 underline hover:text-gray-200"
          >
            {`Confirmar asistencia ${'>'}`}
          </a>
        </div>
        {/* Images right */}
        <div className="w-full h-full relative flex items-center">
          <div className="w-full h-[60%] bg-blue-900">
            {/* <img
            className="rounded-lg absolute top-0 left-0 z-10 transition-transform transform hover:scale-110"
